import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import ProviderCard from '../components/shared/ProviderCard';
import { providerAPI } from '../utils/api';

const CATEGORIES = [
  { name: 'Electrician', icon: '⚡', color: '#4f7fff', desc: 'Wiring, AC, Repairs' },
  { name: 'Plumber', icon: '🔧', color: '#10d9a0', desc: 'Pipes, Taps, Tanks' },
  { name: 'Carpenter', icon: '🪚', color: '#f59e0b', desc: 'Furniture, Doors' },
  { name: 'Painter', icon: '🎨', color: '#a78bfa', desc: 'Wall, Texture, Polish' },
  { name: 'Cleaner', icon: '🧹', color: '#f43f5e', desc: 'Deep, Sofa, Office' },
  { name: 'ACTechnician', icon: '❄️', color: '#38bdf8', desc: 'Install, Service, Gas' },
];

const STATS = [
  { label: 'Verified Providers', value: '2,400+' },
  { label: 'Happy Customers', value: '18,000+' },
  { label: 'Cities Covered', value: '50+' },
  { label: 'Jobs Completed', value: '85,000+' },
];

export default function LandingPage() {
  const navigate = useNavigate();
  const [search, setSearch] = useState('');
  const [topProviders, setTopProviders] = useState([]);

  useEffect(() => {
    providerAPI.getTop({ limit: 6 }).then(r => setTopProviders(r.data.data)).catch(() => {});
  }, []);

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />

      {/* ── Hero ─────────────────────────────────────────────── */}
      <section style={{
        position: 'relative', overflow: 'hidden',
        padding: '100px 24px 80px',
        background: 'radial-gradient(ellipse 80% 60% at 50% -10%, rgba(79,127,255,0.15) 0%, transparent 70%)',
      }}>
        {/* grid bg */}
        <div style={{
          position: 'absolute', inset: 0, opacity: 0.04,
          backgroundImage: 'linear-gradient(var(--border) 1px, transparent 1px), linear-gradient(90deg, var(--border) 1px, transparent 1px)',
          backgroundSize: '40px 40px',
        }} />

        <div className="page-container" style={{ textAlign: 'center', position: 'relative' }}>
          <div className="badge badge-accent animate-fade" style={{ marginBottom: 20, fontSize: 12 }}>
            🚀 India's Trusted Local Services Platform
          </div>

          <h1 style={{ fontSize: 'clamp(36px, 6vw, 72px)', fontWeight: 800, lineHeight: 1.1, marginBottom: 20 }}
            className="animate-fade">
            Find Skilled Pros<br />
            <span style={{ color: 'var(--accent)' }}>Near You, Instantly</span>
          </h1>

          <p style={{ fontSize: 18, color: 'var(--text-secondary)', maxWidth: 540, margin: '0 auto 40px', lineHeight: 1.7 }}
            className="animate-fade">
            Book verified electricians, plumbers, carpenters & more.
            Real-time tracking, secure payments, guaranteed quality.
          </p>

          {/* Search Bar */}
          <div style={{
            display: 'flex', gap: 8, maxWidth: 560, margin: '0 auto 48px',
            background: 'var(--bg-card)', border: '1px solid var(--border)',
            borderRadius: 'var(--radius-lg)', padding: 8,
          }} className="animate-fade">
            <input
              className="form-input"
              style={{ background: 'transparent', border: 'none', fontSize: 16, flex: 1 }}
              placeholder="What service do you need?"
              value={search}
              onChange={e => setSearch(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && navigate(`/search?q=${search}`)}
            />
            <button className="btn btn-primary" onClick={() => navigate(`/search?q=${search}`)}>
              Search
            </button>
          </div>

          {/* Stats */}
          <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center', gap: 32 }}>
            {STATS.map(s => (
              <div key={s.label} style={{ textAlign: 'center' }}>
                <div style={{ fontSize: 28, fontWeight: 800, fontFamily: 'var(--font-display)', color: 'var(--accent)' }}>{s.value}</div>
                <div style={{ fontSize: 12, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: 1 }}>{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Categories ───────────────────────────────────────── */}
      <section style={{ padding: '60px 24px' }}>
        <div className="page-container">
          <h2 style={{ textAlign: 'center', fontSize: 32, fontWeight: 800, marginBottom: 8 }}>
            What do you need help with?
          </h2>
          <p style={{ textAlign: 'center', color: 'var(--text-secondary)', marginBottom: 40 }}>
            Choose from our wide range of verified home services
          </p>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: 16 }}>
            {CATEGORIES.map((cat, i) => (
              <div key={cat.name}
                onClick={() => navigate(`/search?category=${cat.name}`)}
                className="card card-hover"
                style={{
                  textAlign: 'center', padding: 28, cursor: 'pointer',
                  animationDelay: `${i * 0.05}s`,
                }}
              >
                <div style={{
                  width: 60, height: 60, borderRadius: 16, margin: '0 auto 14px',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 28, background: `${cat.color}18`,
                }}>{cat.icon}</div>
                <div style={{ fontWeight: 700, fontFamily: 'var(--font-display)', fontSize: 15 }}>{cat.name}</div>
                <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 4 }}>{cat.desc}</div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Top Providers ────────────────────────────────────── */}
      {topProviders.length > 0 && (
        <section style={{ padding: '60px 24px', background: 'var(--bg-secondary)' }}>
          <div className="page-container">
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 32 }}>
              <div>
                <h2 style={{ fontSize: 28, fontWeight: 800 }}>Top Rated Providers</h2>
                <p style={{ color: 'var(--text-secondary)', marginTop: 4 }}>Handpicked by our quality team</p>
              </div>
              <button className="btn btn-ghost" onClick={() => navigate('/search')}>View All →</button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 16 }}>
              {topProviders.map(p => <ProviderCard key={p._id} provider={p} />)}
            </div>
          </div>
        </section>
      )}

      {/* ── How It Works ─────────────────────────────────────── */}
      <section style={{ padding: '80px 24px' }}>
        <div className="page-container">
          <h2 style={{ textAlign: 'center', fontSize: 32, fontWeight: 800, marginBottom: 8 }}>How SkillBridge Works</h2>
          <p style={{ textAlign: 'center', color: 'var(--text-secondary)', marginBottom: 60 }}>
            Get help at your doorstep in 3 simple steps
          </p>

          <div className="grid-3">
            {[
              { step: '01', icon: '🔍', title: 'Search & Filter', desc: 'Find verified professionals near you filtered by skills, ratings, and price.' },
              { step: '02', icon: '📅', title: 'Book Instantly', desc: 'Select a time slot, describe your problem, and send a booking request.' },
              { step: '03', icon: '⭐', title: 'Get it Done & Rate', desc: 'Track your provider live, pay securely, and rate their work after completion.' },
            ].map((s, i) => (
              <div key={i} className="card" style={{ textAlign: 'center', position: 'relative', overflow: 'hidden' }}>
                <div style={{
                  position: 'absolute', top: 12, right: 16,
                  fontSize: 60, fontWeight: 900, fontFamily: 'var(--font-display)',
                  color: 'var(--border)', lineHeight: 1,
                }}>{s.step}</div>
                <div style={{ fontSize: 40, marginBottom: 16 }}>{s.icon}</div>
                <h3 style={{ fontWeight: 700, marginBottom: 10 }}>{s.title}</h3>
                <p style={{ color: 'var(--text-secondary)', fontSize: 14, lineHeight: 1.6 }}>{s.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── CTA ──────────────────────────────────────────────── */}
      <section style={{
        padding: '80px 24px',
        background: 'radial-gradient(ellipse at center, rgba(79,127,255,0.1) 0%, transparent 70%)',
        textAlign: 'center',
      }}>
        <div className="page-container">
          <h2 style={{ fontSize: 36, fontWeight: 800, marginBottom: 16 }}>Ready to Get Started?</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: 16, marginBottom: 32 }}>
            Join thousands of customers and providers on SkillBridge
          </p>
          <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
            <button className="btn btn-primary btn-lg" onClick={() => navigate('/search')}>
              🔍 Find a Professional
            </button>
            <button className="btn btn-secondary btn-lg" onClick={() => navigate('/register?role=provider')}>
              🛠️ Offer Your Services
            </button>
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer style={{ borderTop: '1px solid var(--border)', padding: '32px 24px', textAlign: 'center' }}>
        <div style={{ fontFamily: 'var(--font-display)', fontWeight: 800, fontSize: 18, marginBottom: 8 }}>
          ⚡ Skill<span style={{ color: 'var(--accent)' }}>Bridge</span>
        </div>
        <p style={{ color: 'var(--text-muted)', fontSize: 13 }}>
          © 2024 SkillBridge. Connecting skilled professionals with customers across India.
        </p>
      </footer>
    </div>
  );
}
